with detail = 1 {
    with link = "line.dk.VGS" {
        track(:first :pax :removed, path("d1.dk.vgs")[:var.yn, :gri.yv]);
    }

    with link = "line.dk.VKB" {
        track(:first :double :cat:ac25 :pax,
                path("d1.dk.vkb")[:vig.yk, :kal.yv]
        );
    }

    with link = "line.dk.VLH" {
        let vh = path("d1.dk.vlh");

        with railway = :first :double :cat:dc15 :pax {
            track(vh[:hvf.yv, :van.yf]);
            track(vh[:van.yf, :hel.yv]);
        }
    }

    with link = "line.dk.VLV" {
        let vl = path("d1.dk.vlv");

        with railway = :first :pax {
            track(vl[:vem.yl, :lem.yt]);
            track(vl[:lem.yt, :lem]);
        }
    }

    with link = "line.dk.VNT" {
        let vt = path("d1.dk.vnt");

        track(:first :pax, vt[:var.yn, :nor]);
        track(:first :pax :removed, vt[:nor, :tar.yn]);
    }

    with link = "line.dk.VRS" {
        track(:first :double :cat:ac25 :pax,
                path("d1.dk.vrs")[:vig.yr, :kva.yk]
        );
    }

    with link = "line.dk.VVG" {
        track(:first :pax :removed, path("d1.dk.vvg")[:ven, :gri.yh]);
    }
}

